class RecordingPage extends HookConsumerWidget {
  const RecordingPage({
    required this.sessionId,
    required this.sessionCreatedAt,
    required this.teamId,
    super.key,
  });

  final String sessionId;
  final DateTime sessionCreatedAt;
  final String teamId;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final previewKey = useMemoized(() => ValueKey('camera_preview_$sessionId'));
    final isRecording = useValueNotifier(false);
    final recordingTimerCount = useValueNotifier(0);
    final selected = useValueNotifier<CameraConfigurationDisplayType?>(null);
    final isLatestAnalysisResultCardVisible = useValueNotifier(false);
    final currentOrientation =
        useValueNotifier(NativeDeviceOrientation.unknown);
    final notifier = ref.watch(cameraControllerProvider.notifier);
    final analysisType = ref.watch(
      cameraControllerProvider.select((value) => value.analysisType),
    );
    final isSingleTeam = useSingleTeamCheck();

    // Coach mark keys
    final recordButtonKey = useMemoized(() => GlobalKey());
    final analysisModeKey = useMemoized(() => GlobalKey());
    final focusButtonKey = useMemoized(() => GlobalKey());
    final configurationKey = useMemoized(() => GlobalKey());

    // Camera and session related states
    final cameraId = useRef<int?>(null);
    final subscription = useRef<StreamSubscription?>(null);
    final recordingTimer = useRef<Timer?>(null);
    final lastRecordingActionTime = useRef<DateTime?>(null);

    // cameraController を watch しないと、initializeCamera で初期化された CameraController が破棄される (watch している Widget がなくなるため)
    // 破棄されると ControlPanel などで参照している値が null になってしまう。
    ref.watch(cameraControllerProvider.select((value) => value.cameraMode));

    // Tutorial state
    final tutorialState = ref.watch(recordingTutorialProvider);
    final tutorialNotifier = ref.watch(recordingTutorialProvider.notifier);
    final isShowingCoachMarks = useValueNotifier(false);

    final launchTutorialVideoUrl = useTutorialVideo(isForRecording: true);

    // Use accelerometer orientation detection hook
    useAccelerometerOrientation(
      config: AccelerometerOrientationConfig(
        showMismatchDialog: !isShowingCoachMarks.value,
      ),
    );

    useEffect(() {
      if (!isSingleTeam) return null;
      final fallback = analysisType.fallbackForSingleTeam();
      if (analysisType != fallback) {
        Future.microtask(() async {
          await notifier.setAnalysisType(fallback);
        });
      }
      return null;
    }, [isSingleTeam, analysisType, notifier]);

    // Camera initialization function
    Future<
        ({
          bool recordingDirectoryInitialized,
          bool cameraIdInitialized,
        })> initializeCamera() async {
      final recordingDirectory = await notifier.initializeRecordingDirectory(
        sessionId,
        sessionCreatedAt,
      );

      cameraId.value = await notifier.configureSession(
        platform.isIos
            ? () => tapRecordingButton(
                  context: context,
                  ref: ref,
                  isRecording: isRecording,
                  isProcessing: isProcessing,
                  currentOrientation: currentOrientation,
                  recordingTimerCount: recordingTimerCount,
                  recordingTimer: recordingTimer,
                )
            : null,
      );
      return (
        recordingDirectoryInitialized: recordingDirectory != null,
        cameraIdInitialized: cameraId.value != null,
      );
    }

    final cameraInitialization = useFuture(useMemoized(initializeCamera));

    // Show coach marks after camera initialization
    useEffect(() {
      if (cameraInitialization.hasData &&
          cameraInitialization.data!.cameraIdInitialized &&
          !tutorialState.isLoading &&
          !tutorialState.hasShownTutorial) {
        WidgetsBinding.instance.addPostFrameCallback((_) async {
          isShowingCoachMarks.value = true;
          RecordingCoachMarks.show(
            context: context,
            targets: RecordingCoachMarkTargets(
              recordButtonKey: recordButtonKey,
              analysisModeKey: analysisModeKey,
              focusButtonKey: focusButtonKey,
            ),
            onFinish: () async {
              isShowingCoachMarks.value = false;
              await tutorialNotifier.markTutorialAsShown();
            },
            launchTutorialVideoUrl: launchTutorialVideoUrl,
          );
        });
      }
      return null;
    }, [cameraInitialization.hasData, tutorialState]);

    // Acceleration sensor subscription and resource management
    useEffectOnce(() {
      // Subscribe to acceleration sensor events
      subscription.value = accelerometerEventStream().listen(
        AccelerationController.getSingletonObject().handle,
        onError: AccelerationController.getSingletonObject().handleError,
        cancelOnError: true,
      );

      // Screen settings
      WakelockPlus.enable();
      SystemChrome.setEnabledSystemUIMode(SystemUiMode.immersiveSticky);

      // Cleanup function
      return () {
        recordingTimer.value?.cancel();
        recordingTimer.value = null;
        isRecording.value = false;

        // Unsubscribe from acceleration sensor
        if (subscription.value != null) {
          subscription.value!.cancel();
          subscription.value = null;
        }

        // Release camera resources
        if (cameraId.value != null) {
          // ここで ref.read(cameraControllerProvider.notifier) をすでに破棄された
          // notifier を使用しているためエラーが発生する。
          notifier.closeSession();
        }

        // Restore screen settings
        SystemChrome.setEnabledSystemUIMode(SystemUiMode.edgeToEdge);
        ScreenOrientation.setDefault();
        WakelockPlus.disable();
      };
    });

    // Build UI based on initialization state
    if (!cameraInitialization.hasData) return const CustomLoadingIndicator();

    // Recording directory initialization failed screen
    if (!cameraInitialization.data!.recordingDirectoryInitialized) {
      return _buildRecordingDirectoryInitializationFailedUI(context);
    }

    // Permission denied screen if camera ID is null
    if (!cameraInitialization.data!.cameraIdInitialized) {
      return _buildPermissionDeniedUI(context);
    }

    // Main UI (preview and controls)
    final previewWidget = _buildCameraPreview(
      context,
      ref,
      previewKey: previewKey,
      cameraId: cameraId,
      recordingTimer: recordingTimer,
      currentOrientation: currentOrientation,
      recordingTimerCount: recordingTimerCount,
      isRecording: isRecording,
      isProcessing: isProcessing,
      selected: selected,
      isLatestAnalysisResultCardVisible: isLatestAnalysisResultCardVisible,
      recordButtonKey: recordButtonKey,
      analysisModeKey: analysisModeKey,
      focusButtonKey: focusButtonKey,
      configurationKey: configurationKey,
      isShowingCoachMarks: isShowingCoachMarks,
      launchTutorialVideoUrl: launchTutorialVideoUrl,
    );

    // Add volume key handler based on platform
    return platform.isIos
        ? previewWidget
        : VolumeKeyHandler(
            enable: true,
            onPressed: (VolumeKey volumeKey) {
              _onVolumeKeyPressed(
                context: context,
                ref: ref,
                isRecording: isRecording,
                isProcessing: isProcessing,
                currentOrientation: currentOrientation,
                recordingTimerCount: recordingTimerCount,
                recordingTimer: recordingTimer,
              );
            },
            child: previewWidget,
          );
  }

  // UI for when camera permission is denied
  Widget _buildPermissionDeniedUI(BuildContext context) {
    return Scaffold(
      appBar: CustomAppBar(
        isBackNavigation: true,
        backgroundColor: ColorManager.cameraControlBackground,
      ),
      backgroundColor: Colors.black,
      body: Center(
        child: Container(
          padding: const EdgeInsets.all(10),
          child: Text(
            context.l10n.recording_page__not_permitted,
            style: const TextStyle(color: Colors.white),
          ),
        ),
      ),
    );
  }

  // UI for when recording directory initialization failed
  Widget _buildRecordingDirectoryInitializationFailedUI(
    BuildContext context,
  ) {
    return Scaffold(
      appBar: CustomAppBar(
        isBackNavigation: true,
        backgroundColor: ColorManager.cameraControlBackground,
      ),
      backgroundColor: Colors.black,
      body: Center(
        child: Container(
          padding: const EdgeInsets.all(10),
          child: Text(
            context
                .l10n.recording_page__recording_directory_initialization_failed,
            style: const TextStyle(color: Colors.white),
          ),
        ),
      ),
    );
  }

  // Camera preview and control UI
  Widget _buildCameraPreview(
    BuildContext context,
    WidgetRef ref, {
    required ValueKey previewKey,
    required ObjectRef<int?> cameraId,
    required ObjectRef<Timer?> recordingTimer,
    required ValueNotifier<NativeDeviceOrientation> currentOrientation,
    required ValueNotifier<int> recordingTimerCount,
    required ValueNotifier<bool> isRecording,
    required ValueNotifier<bool> isProcessing,
    required ValueNotifier<CameraConfigurationDisplayType?> selected,
    required ValueNotifier<bool> isLatestAnalysisResultCardVisible,
    required GlobalKey recordButtonKey,
    required GlobalKey analysisModeKey,
    required GlobalKey focusButtonKey,
    required GlobalKey configurationKey,
    required ValueNotifier<bool> isShowingCoachMarks,
    required VoidCallback launchTutorialVideoUrl,
  }) {
    // Don't show preview if camera ID is null
    if (cameraId.value == null) {
      return const SizedBox.shrink();
    }

    return Stack(
      children: [
        // Camera preview
        SizedBox(
          width: MediaQuery.of(context).size.width,
          height: MediaQuery.of(context).size.height,
          child: FittedBox(
            fit: BoxFit.cover,
            child: CameraPreviewView(
              key: previewKey,
              cameraId: cameraId.value!,
            ),
          ),
        ),
        // Orientation detection and control UI
        _OrientationAbsorber(
          onOrientationChanged: (orientation) {
            currentOrientation.value = orientation;
          },
          child: _TranslucentPointer(
            child: Material(
              color: Colors.transparent,
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.stretch,
                children: [
                  HookBuilder(
                    builder: (context) {
                      final isCoachMarksVisible =
                          useValueListenable(isShowingCoachMarks);
                      // Camera recording UI top section
                      return RecordingAppBar(
                        currentOrientation: currentOrientation,
                        isRecording: isRecording,
                        isLatestAnalysisResultCardVisible:
                            isLatestAnalysisResultCardVisible,
                        recordingTimerCount: recordingTimerCount,
                        selected: selected,
                        analysisModeKey: analysisModeKey,
                        onShowCoachMarks: isCoachMarksVisible
                            ? null
                            : () {
                                isShowingCoachMarks.value = true;
                                RecordingCoachMarks.show(
                                  context: context,
                                  targets: RecordingCoachMarkTargets(
                                    recordButtonKey: recordButtonKey,
                                    analysisModeKey: analysisModeKey,
                                    focusButtonKey: focusButtonKey,
                                  ),
                                  onFinish: () {
                                    isShowingCoachMarks.value = false;
                                  },
                                  launchTutorialVideoUrl:
                                      launchTutorialVideoUrl,
                                );
                              },
                      );
                    },
                  ),
                  // Latest analysis result card
                  HookBuilder(
                    builder: (context) {
                      final isVisible =
                          useValueListenable(isLatestAnalysisResultCardVisible);
                      final recording = useValueListenable(isRecording);
                      return Visibility(
                        maintainState: true,
                        visible: isVisible && !recording,
                        child: LatestAnalysisResultCard(
                          sessionId: sessionId,
                          teamId: teamId,
                          orientation: currentOrientation,
                        ),
                      );
                    },
                  ),
                  // Configuration container
                  Expanded(
                    child: ConfigurationContainer(
                      key: configurationKey,
                      isRecording: isRecording,
                      recordingTimerCount: recordingTimerCount,
                      orientation: currentOrientation,
                      selectedDisplayType: selected,
                    ),
                  ),
                  // Control panel
                  HookBuilder(
                    builder: (context) {
                      final showingCoachMarks =
                          useValueListenable(isShowingCoachMarks);
                      final processing = useValueListenable(isProcessing);
                      return GestureDetector(
                        behavior: HitTestBehavior.opaque,
                        onTap: () {},
                        child: ControlPanel(
                          orientation: currentOrientation,
                          selected: selected,
                          isRecording: isRecording,
                          recordButtonKey: recordButtonKey,
                          focusButtonKey: focusButtonKey,
                          analysisModeKey: analysisModeKey,
                          isButtonDisabled: showingCoachMarks || processing,
                          onTapRecordingButton: () => tapRecordingButton(
                            context: context,
                            ref: ref,
                            isRecording: isRecording,
                            isProcessing: isProcessing,
                            currentOrientation: currentOrientation,
                            recordingTimerCount: recordingTimerCount,
                            recordingTimer: recordingTimer,
                          ),
                        ),
                      );
                    },
                  ),
                ],
              ),
            ),
          ),
        ),
        // For snackbar display
        const _TranslucentPointer(
          child: Scaffold(backgroundColor: Colors.transparent),
        ),
      ],
    );
  }

  Future<void> startRecording({
    required BuildContext context,
    required WidgetRef ref,
    required ValueNotifier<NativeDeviceOrientation> currentOrientation,
    required ValueNotifier<int> recordingTimerCount,
    required ValueNotifier<bool> isRecording,
    required ValueNotifier<bool> isProcessing,
    required ObjectRef<Timer?> recordingTimer,
  }) async {
    isProcessing.value = true;

    await ref.read(cameraControllerProvider.notifier).startRecording();

    recordingTimerCount.value = 0;
    recordingTimer.value = Timer.periodic(
      const Duration(milliseconds: 1000),
      (Timer timer) {
        recordingTimerCount.value += 1;

        final analysisType = ref.watch(
          cameraControllerProvider.select((value) => value.analysisType),
        );

        final threshold = [AnalysisType.pitchingAll, AnalysisType.hittingAll]
                .contains(analysisType)
            ? 120
            : 10;
        if (recordingTimerCount.value >= threshold) {
          stopRecording(
            context: context,
            ref: ref,
            recordingTimerCount: recordingTimerCount,
            isRecording: isRecording,
            isProcessing: isProcessing,
            recordingTimer: recordingTimer,
            currentOrientation: currentOrientation,
          );
        }
      },
    );

    isRecording.value = true;
    isProcessing.value = false;
  }

  Future<void> stopRecording({
    required BuildContext context,
    required WidgetRef ref,
    required ValueNotifier<int> recordingTimerCount,
    required ValueNotifier<bool> isRecording,
    required ValueNotifier<bool> isProcessing,
    required ObjectRef<Timer?> recordingTimer,
    required ValueNotifier<NativeDeviceOrientation> currentOrientation,
  }) async {
    // Guard against multiple calls or race conditions
    if (recordingTimer.value == null) {
      return;
    }

    isProcessing.value = true;

    recordingTimer.value!.cancel();
    recordingTimer.value = null;

    // NOTE: _cameraController.stopRecording causes a delay to save a video file.

    // NOTE: Use `listenProviderWithLoadingDialogAndSnackbar` normally to show a loading dialog.
    // But it is difficult to use the method for only a specific method of a provider.
    final dialog = showLoadingDialog(context: context);
    final recordedVideoData = await ref
        .read(cameraControllerProvider.notifier)
        .stopRecordingAndSaveToLocalStorage();
    if (context.mounted) {
      await popLoadingDialog(context: context, dialog: dialog);
    }

    ref.read(uploadQueueProvider).addUploadTask(recordedVideoData);

    ScreenOrientation.setDefault();
    recordingTimerCount.value = 0;
    isRecording.value = false;
    isProcessing.value = false;
  }

  Future<void> tapRecordingButton({
    required BuildContext context,
    required WidgetRef ref,
    required ValueNotifier<bool> isRecording,
    required ValueNotifier<bool> isProcessing,
    required ValueNotifier<NativeDeviceOrientation> currentOrientation,
    required ValueNotifier<int> recordingTimerCount,
    required ObjectRef<Timer?> recordingTimer,
  }) async {
    // Prevent duplicate taps while processing
    if (isProcessing.value) {
      return;
    }

    if (isRecording.value) {
      await stopRecording(
        context: context,
        ref: ref,
        recordingTimerCount: recordingTimerCount,
        isRecording: isRecording,
        isProcessing: isProcessing,
        recordingTimer: recordingTimer,
        currentOrientation: currentOrientation,
      );
    } else {
      await startRecording(
        context: context,
        ref: ref,
        currentOrientation: currentOrientation,
        recordingTimerCount: recordingTimerCount,
        recordingTimer: recordingTimer,
        isRecording: isRecording,
        isProcessing: isProcessing,
      );
    }
  }

  void _onVolumeKeyPressed({
    required BuildContext context,
    required WidgetRef ref,
    required ValueNotifier<bool> isRecording,
    required ValueNotifier<bool> isProcessing,
    required ValueNotifier<NativeDeviceOrientation> currentOrientation,
    required ValueNotifier<int> recordingTimerCount,
    required ObjectRef<Timer?> recordingTimer,
  }) {
    if (recordingTimer.value == null && isRecording.value) {
      // Do not respond while loadingDialog is displayed
      return;
    }
    tapRecordingButton(
      context: context,
      ref: ref,
      isRecording: isRecording,
      isProcessing: isProcessing,
      currentOrientation: currentOrientation,
      recordingTimerCount: recordingTimerCount,
      recordingTimer: recordingTimer,
    );
  }
}

/// Absorbs screen rotation and forces the child to always be drawn
/// as if in normal Portrait orientation (portraitUp).
class _OrientationAbsorber extends StatelessWidget {
  final Widget child;
  final ValueChanged<NativeDeviceOrientation>? onOrientationChanged;

  const _OrientationAbsorber({
    required this.child,
    this.onOrientationChanged,
  });

  @override
  Widget build(BuildContext context) {
    return NativeDeviceOrientationReader(
      builder: (context) {
        final orientation = NativeDeviceOrientationReader.orientation(context);
        if (onOrientationChanged != null) {
          onOrientationChanged!(orientation);
        }

        final turns = {
          NativeDeviceOrientation.unknown: 0,
          NativeDeviceOrientation.portraitUp: 0,
          NativeDeviceOrientation.landscapeRight: 1,
          NativeDeviceOrientation.portraitDown: 2,
          NativeDeviceOrientation.landscapeLeft: 3,
        }[orientation]!;

        final original = MediaQuery.of(context);
        final modified = original.copyWith(
          size: _rotateSize(original.size, turns),
          padding: _rotateEdgeInsets(original.padding, turns),
          viewPadding: _rotateEdgeInsets(original.viewPadding, turns),
          viewInsets: _rotateEdgeInsets(original.viewInsets, turns),
          systemGestureInsets:
              _rotateEdgeInsets(original.systemGestureInsets, turns),
        );

        return RotatedBox(
          quarterTurns: turns,
          child: MediaQuery(
            data: modified,
            child: child,
          ),
        );
      },
    );
  }

  Size? _rotateSize(Size? src, int turns) {
    if (src == null) {
      return null;
    }
    return turns % 2 == 1 ? src.flipped : src;
  }

  EdgeInsets _rotateEdgeInsets(EdgeInsets src, int turns) {
    switch (turns % 4) {
      case 0:
        return src;
      case 1:
        return EdgeInsets.fromLTRB(src.top, src.right, src.bottom, src.left);
      case 2:
        return EdgeInsets.fromLTRB(src.right, src.bottom, src.left, src.top);
      default:
        return EdgeInsets.fromLTRB(src.bottom, src.left, src.top, src.right);
    }
  }
}

/// Routes pointer events to the child widget as well as to
/// an overlapping widget below.
class _TranslucentPointer extends SingleChildRenderObjectWidget {
  const _TranslucentPointer({
    super.child,
  });

  @override
  _RenderTranslucentPointer createRenderObject(BuildContext context) {
    return _RenderTranslucentPointer();
  }
}

class _RenderTranslucentPointer extends RenderProxyBox {
  @override
  bool hitTest(BoxHitTestResult result, {required Offset position}) {
    super.hitTest(result, position: position);
    return false;
  }
}

